SELECT DISTINCT employee_id AS employeeId, DATE_FORMAT(stat_hour, '%Y-%m-%d %H:00:00') AS statHour FROM ( SELECT employee_id, message_timestamp AS stat_hour FROM dashboard_message WHERE message_timestamp IS NOT NULL AND employee_id IN
#{employeeId}
UNION ALL SELECT employee_id, COALESCE(start_time, created_at) AS stat_hour FROM dashboard_conversation_turn WHERE (start_time IS NOT NULL OR created_at IS NOT NULL) AND employee_id IN
#{employeeId}
UNION ALL SELECT employee_id, COALESCE(occurred_at, created_at) AS stat_hour FROM dashboard_transcript_issue WHERE (occurred_at IS NOT NULL OR created_at IS NOT NULL) AND employee_id IN
#{employeeId}
) AS all_hours WHERE stat_hour IS NOT NULL

SELECT COUNT(*)
FROM dashboard_transcript_issue
WHERE (occurred_at IS NOT NULL OR created_at IS NOT NULL)
  AND employee_id = #{employeeId}
  AND DATE_FORMAT(COALESCE(occurred_at, created_at), '%Y-%m-%d %H:00:00') = #{statHour}
